1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Damage = { itemType: string; amount: number };
14	
15	export type ClaimStep = {
16	  op: "claim";
17	  policy: number;
18	  incident: { cause: string; damages: Damage[] };
19	};
20	
21	export type Step = QuoteStep | ClaimStep;
22	
23	export type Scenario = {
24	  customer: { yearsWithMHPCO: number };
25	  steps: Step[];
26	};
27	
28	export type QuoteResult = { premium: number };
29	export type ClaimResult = { payout: number; remainingCap: number };
30	export type StepResult = QuoteResult | ClaimResult;
31	
32	export type ScenarioResult = {
33	  results: StepResult[];
34	};
35	
36	// Quote constants
37	const PROCESSING_FEE = 5;
38	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
39	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
40	const BLOCK_OF_THREE_DISCOUNT = 15;
41	const CURSE_SURCHARGE_RATE = 0.5;
42	const HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
43	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
44	const LOYALTY_YEARS_THRESHOLD = 2;
45	const LOYALTY_DISCOUNT_RATE = 0.2;
46	
47	type CatalogEntry = { basePremium: number; insuranceValue: number };
48	
49	const ITEM_CATALOG: Record<string, CatalogEntry> = {
50	  sword: { basePremium: 100, insuranceValue: 1000 },
51	  amulet: { basePremium: 60, insuranceValue: 600 },
52	  staff: { basePremium: 80, insuranceValue: 800 },
53	  potion: { basePremium: 40, insuranceValue: 400 },
54	  rune: { basePremium: 25, insuranceValue: 250 },
55	  moonstone: { basePremium: 25, insuranceValue: 250 },
56	};
57	
58	const catalogEntryFor = (type: string): CatalogEntry => {
59	  const entry = ITEM_CATALOG[type];
60	  if (!entry) {
61	    throw new Error(`Unknown item type: ${type}`);
62	  }
63	  return entry;
64	};
65	
66	// Claim constants
67	const DEDUCTIBLE = 100;
68	const CAP_MULTIPLIER = 2;
69	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
70	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
71	
72	const BLOCK_OF_THREE_ELIGIBLE_TYPES = ["rune", "moonstone"];
73	
74	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
75	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
76	
77	const countItemsOfType = (items: Item[], type: string): number =>
78	  items.filter((item) => item.type === type).length;
79	
80	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
81	
82	const isCursed = (item: Item): boolean => item.cursed === true;
83	const qualifiesForHighEnchantmentSurcharge = (item: Item): boolean =>
84	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD;
85	
86	const ITEM_SURCHARGE_RATES: ReadonlyArray<{
87	  applies: (item: Item) => boolean;
88	  rate: number;
89	}> = [
90	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
91	  { applies: qualifiesForHighEnchantmentSurcharge, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
92	];
93	
94	const basePremiumFor = (item: Item): number => catalogEntryFor(item.type).basePremium;
95	
96	const surchargesForItem = (item: Item): number => {
97	  const base = basePremiumFor(item);
98	  return ITEM_SURCHARGE_RATES.reduce(
99	    (sum, { applies, rate }) => sum + (applies(item) ? base * rate : 0),
100	    0,
101	  );
102	};
103	
104	const sumItemSpecificSurcharges = (items: Item[]): number =>
105	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
106	
107	const calculateBasePremium = (items: Item[]): number => {
108	  const subtotal = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
109	  const totalDiscount = BLOCK_OF_THREE_ELIGIBLE_TYPES.reduce(
110	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
111	    0,
112	  );
113	  return subtotal - totalDiscount;
114	};
115	
116	const firstContractSurcharge = (basePremium: number): number =>
117	  basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
118	
119	const qualifiesForLoyaltyDiscount = (yearsWithMHPCO: number): boolean =>
120	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
121	
122	const loyaltyDiscount = (basePremium: number, yearsWithMHPCO: number): number =>
123	  qualifiesForLoyaltyDiscount(yearsWithMHPCO) ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
124	
125	const followUpContractDiscount = (basePremium: number, isFollowUp: boolean): number =>
126	  isFollowUp ? basePremium * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
127	
128	const quote = (
129	  step: QuoteStep,
130	  customer: Scenario["customer"],
131	  isFollowUp: boolean,
132	): QuoteResult => {
133	  const basePremium = calculateBasePremium(step.items);
134	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
135	  const premium = Math.ceil(
136	    basePremium +
137	      itemSurcharges +
138	      firstContractSurcharge(basePremium) -
139	      loyaltyDiscount(basePremium, customer.yearsWithMHPCO) -
140	      followUpContractDiscount(basePremium, isFollowUp) +
141	      PROCESSING_FEE,
142	  );
143	  return { premium };
144	};
145	
146	type Policy = { items: Item[]; cap: number };
147	
148	const insuranceSumOf = (items: Item[]): number =>
149	  items.reduce((sum, item) => sum + catalogEntryFor(item.type).insuranceValue, 0);
150	
151	const initialCapFor = (items: Item[]): number => insuranceSumOf(items) * CAP_MULTIPLIER;
152	
153	const findInsuredItem = (policy: Policy, itemType: string): Item | undefined =>
154	  policy.items.find((item) => item.type === itemType);
155	
156	const qualifiesForHighEnchantmentPayoutReduction = (item: Item | undefined): boolean =>
157	  item !== undefined && enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
158	
159	const payoutForDamage = (damage: Damage, insuredItem: Item | undefined): number => {
160	  const reimbursable = qualifiesForHighEnchantmentPayoutReduction(insuredItem)
161	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
162	    : damage.amount;
163	  return Math.max(0, reimbursable - DEDUCTIBLE);
164	};
165	
166	const countDamagesByType = (damages: Damage[]): Map<string, number> =>
167	  damages.reduce((counts, dmg) => {
168	    counts.set(dmg.itemType, (counts.get(dmg.itemType) ?? 0) + 1);
169	    return counts;
170	  }, new Map<string, number>());
171	
172	const assertDamagesWithinPolicy = (damages: Damage[], policy: Policy): void => {
173	  for (const [itemType, count] of countDamagesByType(damages)) {
174	    if (count > countItemsOfType(policy.items, itemType)) {
175	      throw new Error(`Damage count for ${itemType} exceeds insured quantity`);
176	    }
177	  }
178	};
179	
180	const claim = (step: ClaimStep, policy: Policy): ClaimResult => {
181	  assertDamagesWithinPolicy(step.incident.damages, policy);
182	  const grossPayout = step.incident.damages.reduce(
183	    (sum, dmg) => sum + payoutForDamage(dmg, findInsuredItem(policy, dmg.itemType)),
184	    0,
185	  );
186	  const cappedPayout = Math.min(grossPayout, policy.cap);
187	  return { payout: Math.floor(cappedPayout), remainingCap: policy.cap - cappedPayout };
188	};
189	
190	const handleQuoteStep = (
191	  step: QuoteStep,
192	  customer: Scenario["customer"],
193	  policies: Policy[],
194	): QuoteResult => {
195	  const isFollowUp = policies.length > 0;
196	  const result = quote(step, customer, isFollowUp);
197	  policies.push({ items: step.items, cap: initialCapFor(step.items) });
198	  return result;
199	};
200	
201	const handleClaimStep = (step: ClaimStep, policies: Policy[]): ClaimResult => {
202	  const policy = policies[step.policy];
203	  const result = claim(step, policy);
204	  policy.cap = result.remainingCap;
205	  return result;
206	};
