type QuoteContext = { customer: Scenario["customer"]; isFollowUp: boolean };

type PolicyAdjustment = {
  applies: (ctx: QuoteContext) => boolean;
  signedRate: number; // positive = surcharge, negative = discount
};

const POLICY_ADJUSTMENTS: ReadonlyArray<PolicyAdjustment> = [
  { applies: () => true, signedRate: FIRST_CONTRACT_SURCHARGE_RATE },
  {
    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
    signedRate: -LOYALTY_DISCOUNT_RATE,
  },
  { applies: (ctx) => ctx.isFollowUp, signedRate: -FOLLOW_UP_CONTRACT_DISCOUNT_RATE },
];

const sumPolicyAdjustments = (basePremium: number, ctx: QuoteContext): number =>
  POLICY_ADJUSTMENTS.reduce(
    (sum, { applies, signedRate }) => sum + (applies(ctx) ? basePremium * signedRate : 0),
    0,
  );

const quote = (
  step: QuoteStep,
  customer: Scenario["customer"],
  isFollowUp: boolean,
): QuoteResult => {
  const basePremium = calculateBasePremium(step.items);
  const itemSurcharges = sumItemSpecificSurcharges(step.items);
  const policyAdjustments = sumPolicyAdjustments(basePremium, { customer, isFollowUp });
  const premium = Math.ceil(basePremium + itemSurcharges + policyAdjustments + PROCESSING_FEE);
  return { premium };
};
